705: 		p1Stats, p1Found := stats(p1)
706: 		p2Stats, p2Found := stats(p2)
707: 		if !p1Found || !p2Found {
708: 			// prioritize evicting the pod for which no stats were found
709: 			return cmpBool(!p1Found, !p2Found)
710: 		}
711: 
712: 		// adjust p1, p2 usage relative to the request (if any)
713: 		p1Memory := memoryUsage(p1Stats.Memory)
714: 		p1Request := v1resource.GetResourceRequestQuantity(p1, v1.ResourceMemory)
715: 		p1Memory.Sub(p1Request)
716: 
717: 		p2Memory := memoryUsage(p2Stats.Memory)
718: 		p2Request := v1resource.GetResourceRequestQuantity(p2, v1.ResourceMemory)
719: 		p2Memory.Sub(p2Request)
720: 
721: 		// prioritize evicting the pod which has the larger consumption of memory
722: 		return p2Memory.Cmp(*p1Memory)
723: 	}
